import sailpoint.object.Filter;
import sailpoint.object.Identity;
import sailpoint.object.Link;
import sailpoint.object.QueryOptions;
import sailpoint.tools.Util;

Map correlationMap = new HashMap();

if (link != null) {

  String supervisorId = link.getAttribute("SUPERVISOR_ID");

  if (Util.isNotNullOrEmpty(supervisorId)) {

    Filter filter = Filter.ignoreCase(Filter.eq("employeeId", supervisorId));

    QueryOptions ops = new QueryOptions();
    ops.addFilter(filter);

    int totalMatches = context.countObjects(Identity.class, ops);

    if (totalMatches > 1) {

    Iterator itr = context.search(Identity.class, ops, "id");

    while (itr.hasNext()) {

      Identity identity = context.getObjectById(Identity.class, itr.next()[0]);

      if (identity != null && Util.nullSafeContains("employee,contractor,physician", identity.getType())) {

        //In case of multiple matches on SUPERVISOR_ID to employeeId, use whatever matching Identity has type of employee, contractor, or physician
        
        correlationMap.put("identity", identity);
        break; //Don't continue evaluating after we have determined suitable match.

      } //Consider any instance of multiple matches where type is NOT employee, contractor, or physician to be invalid (i.e. don't correlate manager when this scenario is encountered)

    }

      Util.flushIterator(itr);

    } else if (totalMatches == 1) {

      Identity identity = context.getUniqueObject(Identity.class, filter);

      if (identity != null) {

        //In case of single match on SUPERVISOR_ID to employeeId, use matching Identity.

        correlationMap.put("identity", identity);

      }

    }

  }

}

return correlationMap;
